SELECT date
FROM data_points
WHERE value = (
  SELECT MAX(value)
  FROM data_points
);

SELECT metric_name 
FROM air_quality_metrics
WHERE standard_value > (
  SELECT AVG(standard_value) 
  FROM air_quality_metrics
);

SELECT DISTINCT metric_id 
FROM data_points 
WHERE station_id = 1 AND date = '2019-08-28';

SELECT AVG(temperature) AS average_temperature
FROM weather_data
WHERE date = '2019-08-28';
